import{_ as n,o,c as t,ag as a}from"./chunks/framework.B7K4-9EU.js";const h=JSON.parse('{"title":"ADR 001 - Designing and planning in the open","description":"","frontmatter":{"date":"2026-03-12T00:00:00.000Z","title":"ADR 001 - Designing and planning in the open"},"headers":[],"relativePath":"reference/adrs/records/001-open-design-docs.md","filePath":"reference/adrs/records/001-open-design-docs.md","lastUpdated":1776342733000}'),i={name:"reference/adrs/records/001-open-design-docs.md"};function s(r,e,d,c,l,u){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-001-open-design-documentation" tabindex="-1">ADR 001 - Open design documentation <a class="header-anchor" href="#adr-001-open-design-documentation" aria-label="Permalink to &quot;ADR 001 - Open design documentation&quot;">​</a></h1><h2 id="problem-statement" tabindex="-1">Problem Statement <a class="header-anchor" href="#problem-statement" aria-label="Permalink to &quot;Problem Statement&quot;">​</a></h2><p>As Saluki grows, architectural decisions and design rationale are spread across pull requests, issues, and ad-hoc comments with no canonical, discoverable record. How should we capture and communicate design decisions so that current and future contributors can understand why the project is shaped the way it is?</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Saluki is developed in the open. Source code, issues, and pull requests are all public — but the reasoning behind significant design choices is often buried in long PR threads or lost entirely. This makes it hard for new contributors to understand past trade-offs and for existing contributors to recall why a particular path was chosen.</p><p>In the spirit of open development, we want our design and planning process to be equally transparent. A structured, version-controlled home for this information keeps it discoverable, reviewable, and tied to the same repository as the code it describes.</p><h2 id="considered-options" tabindex="-1">Considered Options <a class="header-anchor" href="#considered-options" aria-label="Permalink to &quot;Considered Options&quot;">​</a></h2><ul><li><strong>Continue with ad-hoc documentation in PRs and issues</strong> — no new process; decisions stay where they were discussed.</li><li><strong>Introduce an ADR section only</strong> — add a dedicated section for recording point-in-time architectural decisions.</li><li><strong>Introduce both an ADR section and an RFC/plans section</strong> — add an ADR section for decisions and a separate section for longer-form design proposals and plans (RFCs).</li></ul><h2 id="decision-outcome" tabindex="-1">Decision Outcome <a class="header-anchor" href="#decision-outcome" aria-label="Permalink to &quot;Decision Outcome&quot;">​</a></h2><p>Chosen option: &quot;Introduce both an ADR section and an RFC/plans section&quot;, because each format serves a distinct purpose and together they cover the full spectrum of design documentation we need.</p><p>ADRs are concise, point-in-time records of a decision and its rationale — ideal for capturing <em>what</em> was decided and <em>why</em>. RFCs/plans are longer-form documents suited for proposing and discussing designs <em>before</em> a decision is finalized. Having both gives contributors a clear place to propose ideas (RFCs) and a clear place to record the outcome (ADRs), all within the same public documentation site.</p><h3 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><ul><li>Good, because design rationale becomes discoverable and version-controlled alongside the code.</li><li>Good, because it reinforces Saluki&#39;s commitment to developing in the open — not just the code, but the thinking behind it.</li><li>Good, because separating ADRs from RFCs gives each document type a focused scope, making them easier to write and review.</li><li>Bad, because it introduces a small amount of process overhead when making significant decisions.</li></ul>',13)])])}const m=n(i,[["render",s]]);export{h as __pageData,m as default};
